import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.DGp-bpT-.js";const m=JSON.parse('{"title":"Общение с ботом и правила взаимодействия","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/guide/interaction.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/interaction.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/interaction.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/interaction.md"}]]},"headers":[],"relativePath":"guide/interaction.md","filePath":"guide/interaction.md","lastUpdated":1782748742000}'),l={name:"guide/interaction.md"};function i(d,e,n,s,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="общение-с-ботом-и-правила-взаимодеиствия" tabindex="-1">Общение с ботом и правила взаимодействия <a class="header-anchor" href="#общение-с-ботом-и-правила-взаимодеиствия" aria-label="Permalink to &quot;Общение с ботом и правила взаимодействия&quot;">​</a></h1><p>Платформа SREBot позволяет не только получать автоматический анализ алертов (RCA), но и вести диалог с ботом в чате для уточнения деталей.</p><h2 id="как-задать-уточняющии-вопрос" tabindex="-1">Как задать уточняющий вопрос <a class="header-anchor" href="#как-задать-уточняющии-вопрос" aria-label="Permalink to &quot;Как задать уточняющий вопрос&quot;">​</a></h2><p>Чтобы задать вопрос боту по поводу конкретного инцидента:</p><ol><li>Найдите сообщение бота с анализом (RCA) в Telegram-канале или чате.</li><li>Ответьте на это сообщение (<strong>Reply</strong>) своим вопросом.</li><li>Бот увидит ваш ответ, покажет статус «Анализирую...» и пришлет уточненную информацию.</li></ol><h2 id="свободныи-диалог-произвольные-вопросы" tabindex="-1">Свободный диалог (произвольные вопросы) <a class="header-anchor" href="#свободныи-диалог-произвольные-вопросы" aria-label="Permalink to &quot;Свободный диалог (произвольные вопросы)&quot;">​</a></h2><p>Помимо вопросов по конкретным алертам, вы можете задать боту произвольный диагностический вопрос в любой момент, просто обратившись к нему.</p><h3 id="как-обратиться-к-боту" tabindex="-1">Как обратиться к боту <a class="header-anchor" href="#как-обратиться-к-боту" aria-label="Permalink to &quot;Как обратиться к боту&quot;">​</a></h3><p>Напишите сообщение в чате, упомянув бота:</p><ul><li>По его юзернейму (например, <code>@stage_sre_bot</code>).</li><li>По его отображаемому имени (например, <code>@stage-sre-bot</code> или просто упомянув <code>stage-sre-bot</code> в тексте).</li></ul><p><strong>Примеры свободных запросов:</strong></p><ul><li><em>«@stage_sre_bot проверь логи контейнера backend за последние 2 часа»</em></li><li><em>«@stage_sre_bot собери логи с ошибками в неймспейсе production»</em></li><li><em>«@stage_sre_bot какие инструменты тебе доступны?»</em></li></ul><p>Такой диалог будет сохранен в панели управления как <strong>Пользовательский запрос</strong>, и вы сможете просмотреть всю историю вопросов и ответов на панели управления (они отмечены иконкой сообщения 💬 в списке).</p><h3 id="окно-контекста" tabindex="-1">Окно контекста <a class="header-anchor" href="#окно-контекста" aria-label="Permalink to &quot;Окно контекста&quot;">​</a></h3><p>Бот сохраняет контекст вашей беседы. По умолчанию время жизни контекста (окно, в течение которого вы можете продолжать диалог по цепочке ответов) составляет <strong>12 часов</strong> с момента последнего сообщения. Это позволяет вести непрерывный диалог в течение всего рабочего дня, не боясь потерять историю переписки.</p><h2 id="правила-общения-с-ботом" tabindex="-1">Правила общения с ботом <a class="header-anchor" href="#правила-общения-с-ботом" aria-label="Permalink to &quot;Правила общения с ботом&quot;">​</a></h2><p>Чтобы бот работал эффективно и не тратил ваши токены впустую, соблюдайте следующие правила:</p><h3 id="_1-тематика-вопросов" tabindex="-1">1. Тематика вопросов <a class="header-anchor" href="#_1-тематика-вопросов" aria-label="Permalink to &quot;1. Тематика вопросов&quot;">​</a></h3><p>Бот спроектирован как профессиональный SRE-ассистент. Он отвечает <strong>только на вопросы, связанные с текущим инцидентом</strong>, предоставленным анализом или общими задачами диагностики и обсервабилити.</p><p><strong>Примеры хороших вопросов:</strong></p><ul><li><em>«Покажи логи за последние 10 минут с этой ноды»</em></li><li><em>«Какая загрузка CPU была в момент алерта?»</em></li><li><em>«Какие еще алерты срабатывали в этом кластере за час?»</em></li></ul><p><strong>Защита от оффтопа:</strong> Если вы спросите бота о чем-то, не связанном с инцидентом (например, <em>«расскажи анекдот»</em> или <em>«как дела»</em>), бот вежливо откажется отвечать, чтобы сберечь баланс токенов вашей организации.</p><h3 id="_2-язык-общения" tabindex="-1">2. Язык общения <a class="header-anchor" href="#_2-язык-общения" aria-label="Permalink to &quot;2. Язык общения&quot;">​</a></h3><p>Бот может общаться на разных языках. Язык ответов настраивается в панели управления или через переменную окружения <code>LLM_RESPONSE_LANGUAGE</code>. Если вы хотите, чтобы бот отвечал на русском, убедитесь, что этот параметр установлен в <code>Russian</code>.</p><h3 id="_3-ограничения-лимиты" tabindex="-1">3. Ограничения (Лимиты) <a class="header-anchor" href="#_3-ограничения-лимиты" aria-label="Permalink to &quot;3. Ограничения (Лимиты)&quot;">​</a></h3><p>Для защиты от бесконечных циклов и спама действуют следующие ограничения:</p><ul><li><strong>Кулдаун</strong>: между вопросами одного пользователя должна быть пауза (по умолчанию 10 секунд).</li><li><strong>Максимум вопросов</strong>: на один инцидент можно задать ограниченное количество вопросов (по умолчанию 5). При превышении лимита бот сообщит, что лимит исчерпан.</li></ul><p>Эти параметры настраиваются на стороне бота (<code>FOLLOWUP_COOLDOWN</code>, <code>FOLLOWUP_MAX_TURNS</code>).</p><h2 id="команды-управления-mute-unmute-status" tabindex="-1">Команды управления (Mute / Unmute / Status) <a class="header-anchor" href="#команды-управления-mute-unmute-status" aria-label="Permalink to &quot;Команды управления (Mute / Unmute / Status)&quot;">​</a></h2><p>Вы можете временно приостанавливать отправку анализов тревог с помощью команд управления. Команды можно вводить как со слэшем (<code>/</code>), так и без него.</p><h3 id="_1-временное-отключение-тревог-mute" tabindex="-1">1. Временное отключение тревог (Mute) <a class="header-anchor" href="#_1-временное-отключение-тревог-mute" aria-label="Permalink to &quot;1. Временное отключение тревог (Mute)&quot;">​</a></h3><p>Команда <code>mute [длительность]</code> (или <code>/mute [длительность]</code>) активирует режим тишины.</p><ul><li><strong>Формат длительности</strong>: поддерживает секунды (<code>s</code>), минуты (<code>m</code>), часы (<code>h</code>) и дни (<code>d</code>). Например: <code>30m</code>, <code>2h</code>, <code>1d</code>, <code>1h 30m</code>.</li><li><strong>Значение по умолчанию</strong>: если длительность не указана, режим тишины активируется на <strong>1 час</strong>.</li></ul><p>Применяется в двух режимах:</p><ul><li><strong>Точечный (для конкретной тревоги)</strong>: Отправьте команду <code>mute 2h</code> как <strong>ответ (reply)</strong> на сообщение бота с анализом тревоги (RCA). Бот заглушит только этот тип тревог (по имени алерта, например, <code>HighCpuUsage</code>) в этом чате.</li><li><strong>Глобальный (для всех тревог)</strong>: Отправьте команду <code>mute 2h</code> как обычное сообщение в чат. Бот временно прекратит анализировать любые входящие алерты в этом чате.</li></ul><h3 id="_2-включение-тревог-unmute" tabindex="-1">2. Включение тревог (Unmute) <a class="header-anchor" href="#_2-включение-тревог-unmute" aria-label="Permalink to &quot;2. Включение тревог (Unmute)&quot;">​</a></h3><p>Команда <code>unmute</code> (или <code>/unmute</code>) отключает режим тишины.</p><ul><li><strong>Снятие точечного глушения</strong>: Отправьте <code>unmute</code> как <strong>ответ (reply)</strong> на сообщение бота с анализом тревоги (RCA). Бот разблокирует анализ только для этого типа тревог.</li><li><strong>Полное снятие тишины</strong>: Отправьте <code>unmute</code> как обычное сообщение в чат. Все активные режимы тишины (глобальный и точечные) в этом чате будут сброшены.</li></ul><h3 id="_3-просмотр-состояния-тишины-status" tabindex="-1">3. Просмотр состояния тишины (Status) <a class="header-anchor" href="#_3-просмотр-состояния-тишины-status" aria-label="Permalink to &quot;3. Просмотр состояния тишины (Status)&quot;">​</a></h3><p>Команда <code>status</code> (или <code>/status</code>) выводит список всех активных режимов тишины в текущем чате с указанием оставшегося времени действия для каждого правила.</p><ul><li>Если активных глушений нет, бот пришлет подтверждение, что он работает в обычном режиме.</li></ul><h3 id="_4-адресация-команд-нескольким-ботам" tabindex="-1">4. Адресация команд нескольким ботам <a class="header-anchor" href="#_4-адресация-команд-нескольким-ботам" aria-label="Permalink to &quot;4. Адресация команд нескольким ботам&quot;">​</a></h3><p>Если в одном групповом чате находятся несколько ботов, вы можете направить команду конкретному боту, добавив суффикс <code>@имя_бота</code>:</p><ul><li><code>/mute@SreBotA 30m</code> — включит тишину только для бота <code>@SreBotA</code>.</li><li><code>/status@SreBotB</code> — запросит статус только у бота <code>@SreBotB</code>.</li></ul><p>Если суффикс не указан, команда применится ко всем ботам, имеющим доступ к чтению сообщений чата.</p>',45)])])}const p=t(l,[["render",i]]);export{m as __pageData,p as default};
